import { describe, expect, it } from "vitest";
import { createLimiter } from "../src/limiter.js";

describe("createLimiter", () => {
  describe("shape", () => {
    it("returns an object exposing an allow function", () => {
      const limiter = createLimiter();
      expect(typeof limiter.allow).toBe("function");
    });
  });

  describe("limit enforcement within a window", () => {
    it("allows exactly `limit` calls, then denies further ones", () => {
      const limiter = createLimiter(3, 1000);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 1)).toBe(true);
      expect(limiter.allow("k", 2)).toBe(true);
      expect(limiter.allow("k", 3)).toBe(false);
      expect(limiter.allow("k", 4)).toBe(false);
    });

    it("defaults to a limit of 5", () => {
      const limiter = createLimiter();
      for (let i = 0; i < 5; i++) {
        expect(limiter.allow("k", i)).toBe(true);
      }
      expect(limiter.allow("k", 5)).toBe(false);
    });

    it("uses strictly-less-than comparison (allows up to but not including limit)", () => {
      const limiter = createLimiter(1, 1000);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(false);
    });

    it("denies every call when limit is 0", () => {
      const limiter = createLimiter(0, 1000);
      expect(limiter.allow("k", 0)).toBe(false);
      expect(limiter.allow("k", 100)).toBe(false);
    });
  });

  describe("denied calls record nothing", () => {
    it("a denied call does not consume a future slot", () => {
      // limit 1, window 100. One call at t=0 fills the bucket.
      const limiter = createLimiter(1, 100);
      expect(limiter.allow("k", 0)).toBe(true);
      // Denied at t=50 (t=0 still in window). This must NOT be recorded.
      expect(limiter.allow("k", 50)).toBe(false);
      // At t=101 the only recorded timestamp (0) has expired. If the denied
      // call at 50 had been recorded, this would be blocked.
      expect(limiter.allow("k", 101)).toBe(true);
    });

    it("repeated denials do not accumulate", () => {
      const limiter = createLimiter(1, 100);
      expect(limiter.allow("k", 0)).toBe(true);
      for (const t of [10, 20, 30, 40, 50]) {
        expect(limiter.allow("k", t)).toBe(false);
      }
      // Only the t=0 call was recorded; it expires at t=100.
      expect(limiter.allow("k", 101)).toBe(true);
    });
  });

  describe("sliding window expiry", () => {
    it("frees a slot once an old call falls outside the window", () => {
      const limiter = createLimiter(1, 100);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 99)).toBe(false); // 0 > 99-100=-1 → still counts
      expect(limiter.allow("k", 100)).toBe(true); // 0 > 100-100=0 → expired
    });

    it("treats a call exactly windowMs old as expired (t === now - windowMs)", () => {
      const limiter = createLimiter(1, 60000);
      expect(limiter.allow("k", 0)).toBe(true);
      // now - windowMs === 0 === recorded timestamp → boundary excluded.
      expect(limiter.allow("k", 60000)).toBe(true);
    });

    it("keeps a call that is one ms younger than the window boundary", () => {
      const limiter = createLimiter(1, 60000);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 59999)).toBe(false);
    });

    it("counts only calls within the window when the bucket is full", () => {
      const limiter = createLimiter(2, 100);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 50)).toBe(true);
      expect(limiter.allow("k", 60)).toBe(false); // both 0 and 50 in window
      // At t=100 the call at 0 has expired, leaving one slot (the call at 50).
      expect(limiter.allow("k", 100)).toBe(true);
      expect(limiter.allow("k", 100)).toBe(false); // now 50 and 100 fill it
    });

    it("allows a fresh burst after the whole window has passed", () => {
      const limiter = createLimiter(3, 1000);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(false);
      // After the window, all three expire and a new burst of 3 is allowed.
      expect(limiter.allow("k", 1000)).toBe(true);
      expect(limiter.allow("k", 1000)).toBe(true);
      expect(limiter.allow("k", 1000)).toBe(true);
      expect(limiter.allow("k", 1000)).toBe(false);
    });
  });

  describe("keys are independent buckets", () => {
    it("does not share counts across keys", () => {
      const limiter = createLimiter(1, 1000);
      expect(limiter.allow("a", 0)).toBe(true);
      expect(limiter.allow("b", 0)).toBe(true);
      expect(limiter.allow("a", 0)).toBe(false);
      expect(limiter.allow("b", 0)).toBe(false);
    });

    it("exhausting one key leaves another untouched", () => {
      const limiter = createLimiter(2, 1000);
      expect(limiter.allow("a", 0)).toBe(true);
      expect(limiter.allow("a", 0)).toBe(true);
      expect(limiter.allow("a", 0)).toBe(false);
      expect(limiter.allow("b", 0)).toBe(true);
      expect(limiter.allow("b", 0)).toBe(true);
    });

    it("supports distinct key types as separate buckets", () => {
      const limiter = createLimiter(1, 1000);
      expect(limiter.allow("1", 0)).toBe(true);
      expect(limiter.allow(1, 0)).toBe(true); // number 1 !== string "1"
      expect(limiter.allow("1", 0)).toBe(false);
      expect(limiter.allow(1, 0)).toBe(false);
    });
  });

  describe("`now` validation", () => {
    it("throws TypeError when now is not a number", () => {
      const limiter = createLimiter();
      expect(() => limiter.allow("k", "0")).toThrow(TypeError);
      expect(() => limiter.allow("k", null)).toThrow(TypeError);
      expect(() => limiter.allow("k", undefined)).toThrow(TypeError);
      expect(() => limiter.allow("k")).toThrow(TypeError);
      expect(() => limiter.allow("k", {})).toThrow(TypeError);
      expect(() => limiter.allow("k", true)).toThrow(TypeError);
    });

    it("throws TypeError for non-finite numbers", () => {
      const limiter = createLimiter();
      expect(() => limiter.allow("k", NaN)).toThrow(TypeError);
      expect(() => limiter.allow("k", Infinity)).toThrow(TypeError);
      expect(() => limiter.allow("k", -Infinity)).toThrow(TypeError);
    });

    it("accepts finite numbers including zero and negatives", () => {
      const limiter = createLimiter(1, 1000);
      expect(limiter.allow("a", -500)).toBe(true);
      expect(limiter.allow("b", 0)).toBe(true);
      expect(limiter.allow("c", 12345.6)).toBe(true);
    });

    it("does not record anything when validation fails", () => {
      const limiter = createLimiter(1, 1000);
      expect(() => limiter.allow("k", NaN)).toThrow(TypeError);
      // The bucket is still empty, so a valid call is allowed.
      expect(limiter.allow("k", 0)).toBe(true);
    });
  });

  describe("independent limiter instances", () => {
    it("keeps state separate between limiters", () => {
      const a = createLimiter(1, 1000);
      const b = createLimiter(1, 1000);
      expect(a.allow("k", 0)).toBe(true);
      expect(a.allow("k", 0)).toBe(false);
      expect(b.allow("k", 0)).toBe(true);
    });
  });
});

